  ('police-b20a8cf8-moex-00064', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-d3d0624a', 'sub-police-b20a8cf8-02', NULL, 'essay', '甲因友人遭人埋伏毆打，懷疑是A通風報信。為圖謀報復，邀集乙、丙、
丁等 3人，由乙駕車搭載，並攜帶西瓜刀、球棒等兇器，依甲之指示前
往某店，甲另指示丙邀約 A前來談判，A為壯膽，夥同 B、C到場。雙
方見面一言不合大打出手，甲即指示丙、丁分持西瓜刀追砍 A、球棒追
打 B、C 成傷，並砸壞該店桌椅。乙在旁吶喊加油。前開眾人鬥毆的行
為引起該店顧客恐慌，紛紛逃離，並通知警察到場。請問甲、乙、丙、
丁成立何罪？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "ed7e0d595460", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1208", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "偵查法學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00065', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'essay', '依照我國司法實務及鑑識機關使用之鑑定方法，請回答下列槍彈鑑識問
題：
我國「槍砲彈藥刀械管制條例」除列舉管制制式槍砲外，尚概括管制
「其他可發射金屬或子彈具有殺傷力之各式槍砲」，依據上述，請說明
何謂「殺傷力」？（5分）
承上，我國實務鑑識機關常用性能檢驗法，予以認定槍枝是否具殺傷
力，請說明何謂性能檢驗法？（15 分）
模擬槍經常遭不法之徒改造為具殺傷力槍枝，請說明何謂「模擬槍」？
（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00066', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'essay', '據調查被害人 A 於 1 個月前進入嫌犯 B 住宅後，因故 A 遭 B 勒死，B
並在浴室將 A分屍後，分裝丟棄於附近溪河中；分屍處之浴室牆壁為淺
色磁磚及地板為深色磁磚材質，且均遭清洗過。您是現場勘察人員，針
對本案浴室現場，請說明如何依刑案現場物證鑑定步驟及方法要領，進
行本案血跡類跡證最佳化之處理？（請詳述處理作為及相關運用方法與
要領等）（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00067', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關地下毒品工廠現場各類試劑與工具之研判，請選出正確者：①現場發現有黃樟油（Safrole），', '["現場發現甲胺（Methylamine），可能是製造喵 喵（Mephedrone）之試劑", "現場發現甲胺，可能是製造愷他命（Ketamine）之試劑", "三級丁 氧羰基愷他命（N-BocKetamine）為愷他命之先驅原料  ⑤火災現場發現有雙層玻璃反應槽，但 無冷卻循環設備，不可能為喵喵製造場所", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00068', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關植物類毒品之敘述，請選出正確者：①Fast Corinth V salt test 可作為大麻呈色試驗使用', '["JWH、AM、HU系列均係由大麻植株中提煉而來", "墨西哥鼠尾草（S. divinorum）葉緣呈鋸 齒狀，葉片對生，內含沙維諾林A（salvinorin.A）成分，施用者吸入後會產生類似大麻之迷幻作 用", "相思樹皮可用來製作DMT或死藤水  ⑤大花曼陀羅為多年生、直立性的半落葉性灌木， 主要成分為裸頭草辛（Psilocine）", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00069', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關印痕現場處理方式，請選出正確者：①靜電足跡採取器可使用於乾燥之吸水性及非吸水性物', '["紙板上的灰塵鞋印痕可再實施化學處理以強化顯現", "石膏鑄模時理想的石膏與水分 重量配置比例為1：1", "鞋底圖騰係工廠所製作，故無法產生個化比對之效果", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00070', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '火場可燃性液體殘跡辨識與偵檢要領，請選出正確者：①縱火劑往低處逸流，滲入木板間隙後持', '["黏附於混凝土上之塑膠地板，若滲入液態縱火 劑燃燒後，會形成鬼狀痕跡（ghost pattern）", "可燃性液體吸附劑（Ignitable Liquid Absorbent, ILA）為一親水性粉末，灑在可疑位置之表面後，可吸收殘留之可燃性液體殘跡", "可疑起火處 若有多孔性材質要優先採樣  ⑤光離子化偵測器藉由氫氣和氧氣混合將化合物燃燒產生離子和 電子，藉由光譜顏色變化分辨可疑氣體", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00071', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關文書鑑定之技術與概念，請選出正確者：①將爭議內容以幾何圖形重疊分析相關位置關係，', '["線性光源在暗室內操作，效果較自然光線下好", "透過靜電壓痕顯現 儀，可觀察到筆壓及筆畫之先後次序", "筆跡鑑定之平日字跡（collected writing）及庭書字跡 （requestedwriting）都屬於標準比對檢體  ⑤變異性字跡筆畫之特徵乃是終其一生不會改變", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00072', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關血跡指紋之化學試劑顯現法，請選出正確者：①AmidoBlack試劑是與指紋中的無機物質反', '["Acid Yellow 7試劑係與指紋中的蛋白質反應", "深色物面上之血指紋可以直接用415nm 光源照射，指紋顏色會變深", "血跡指紋系統化處理之次序，蛋白質或血基質之處理應置於最後 ⑤LeucocrystalViolet（LCV）適用於非吸水性檢體上", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00073', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '指紋採證時現場光線之使用與選擇，請選出正確者：①不論是凸起或是凹陷的成型紋，均適用低', '["反射式打光（bounce lighting）適用於不鏽鋼鐵門上之較微弱指紋", "同軸光 （coaxiallighting）適用於具有反射或半反射物面之檢體", "反史托克（anti-stokes）指紋粉末多 由紫外光激發後產生目視可見之螢光  ⑤反射式紫外線影像系統（RUVIS）係使用紫外線照射於 吸水透氣物面檢體以產生螢光", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
